process.on('uncaughtException', (err) => { console.error('uncaughtException', err); process.exit(1); });
```

## 2. No input validation

`/users` takes no input today, but the pattern across the app should include validation. When you add parameterized routes (e.g., `/users/:id`), validate and coerce:

```js
const { z } = require('zod');

const IdParam = z.object({ id: z.coerce.number().int().positive() });

app.get('/users/:id', (req, res, next) => {
  const parsed = IdParam.safeParse(req.params);
  if (!parsed.success) return res.status(400).json({ error: 'Invalid id' });
  // ... use parsed.data.id
});
```

For bodies, gate `express.json()` with a size limit and validate with a schema:

```js
app.use(express.json({ limit: '10kb' }));
```

## 3. Missing security middleware

Add hardening middleware — these are low-effort, high-impact:

```js
