app.use(express.json({ limit: '100kb' }));
app.use(rateLimit({ windowMs: 60_000, max: 100 }));

app.get('/health', (req, res) => res.json({ status: 'ok', timestamp: new Date().toISOString() }));

app.get('/users', async (req, res, next) => {
  try {
    // TODO: authn/authz, pagination, field filtering
    res.json([{ id: 1, name: 'Alice' }, { id: 2, name: 'Bob' }]);
  } catch (err) { next(err); }
});

app.use((req, res) => res.status(404).json({ error: 'Not Found' }));
app.use((err, req, res, _next) => {
  console.error(err);
  res.status(err.status || 500).json({ error: 'Internal Server Error' });
});

const port = Number(process.env.PORT) || 3000;
const server = app.listen(port, () => console.log(`listening on ${port}`));
for (const sig of ['SIGINT', 'SIGTERM']) process.on(sig, () => server.close(() => process.exit(0)));

module.exports = app;
```

---

## Priority order if you only do a few

1. Global error handler + 404 handler (prevents stack-trace leakage).
2. `helmet`, disable `x-powered-by`, JSON body size limit.
3. Rate limiting.
4. AuthN/AuthZ + field filtering on `/users`.
5. Graceful shutdown.

