## Current Issues

The file is small, but it has several gaps common to Express starters:

1. **No global error handler** — any thrown error or rejected promise in a handler will leak stack traces via Express's default error handler (especially with `NODE_ENV` unset).
2. **No 404 handler** — unknown routes fall through with Express's default HTML response.
3. **No input validation** — there are no routes taking user input yet, but there's also no framework in place (e.g., `zod`, `joi`, `express-validator`) for when you add them.
4. **No security middleware** — missing `helmet`, CORS configuration, body-size limits, and rate limiting.
5. **No request logging / correlation IDs** — makes incident response harder.
6. **Server listens unconditionally** — makes the module hard to test and causes port conflicts when imported.
7. **Hardcoded port** — should come from `process.env.PORT`.
8. **No graceful shutdown** — `SIGTERM`/`SIGINT` won't drain in-flight requests.
9. **User data is hardcoded** — not a security issue per se, but email addresses should not be exposed in a `/users` endpoint without authentication/authorization.

## Suggested Rewrite

```js
const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();

// --- Security middleware ---
app.use(helmet());                                  // sensible security headers
app.use(express.json({ limit: '10kb' }));           // cap body size to prevent DoS
app.disable('x-powered-by');                        // don't advertise Express

// Global rate limit (tune per-route as needed)
app.use(rateLimit({
  windowMs: 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
}));

// --- Routes ---
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// Example of per-route input validation using a small inline validator.
// For real projects, prefer zod / joi / express-validator.
app.get('/users/:id', (req, res, next) => {
  const id = Number(req.params.id);
  if (!Number.isInteger(id) || id <= 0 || id > Number.MAX_SAFE_INTEGER) {
    return res.status(400).json({ error: 'Invalid user id' });
  }
  // ... lookup ...
  res.json({ id, name: 'Alice' });  // never echo raw req input into responses
});

app.get('/users', (req, res) => {
  // Consider: auth required? Should email be exposed?
  res.json([
    { id: 1, name: 'Alice' },
    { id: 2, name: 'Bob' },
  ]);
});

// --- 404 handler (must come after routes) ---
app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// --- Global error handler (must have 4 args) ---
// eslint-disable-next-line no-unused-vars
app.use((err, req, res, next) => {
  // Log full error server-side, return sanitized response to client.
  console.error({ msg: 'unhandled_error', err: err.stack, path: req.path });
  const status = err.status || 500;
  res.status(status).json({
    error: status === 500 ? 'Internal server error' : err.message,
  });
});

// --- Server lifecycle ---
if (require.main === module) {
  const port = Number(process.env.PORT) || 3000;
  const server = app.listen(port, () => {
    console.log(`Server running on port ${port}`);
  });

  const shutdown = (signal) => () => {
    console.log(`${signal} received, shutting down`);
    server.close(() => process.exit(0));
    // Force-exit if connections don't drain in time
    setTimeout(() => process.exit(1), 10_000).unref();
