  query('offset').optional().isInt({ min: 0 }).toInt(),
  (req, res) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) return res.status(400).json({ errors: errors.array() });
    // ...
  });
```

Use `express-validator`, `zod`, or `joi` — don't hand-roll regexes for emails, IDs, etc.

## 3. Security hardening middleware

None of these are present; all are standard baseline:

```js
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const cors = require('cors');

app.disable('x-powered-by');                       // don't advertise Express
app.use(helmet());                                 // sensible default headers (CSP, HSTS, etc.)
app.use(express.json({ limit: '10kb' }));          // bound body size — prevents memory DoS
app.use(cors({ origin: ['https://your-app.example'] })); // don't default to *
app.use(rateLimit({ windowMs: 60_000, max: 100 })); // per-IP throttling
