  res.status(err.status || 500).json({
    error: process.env.NODE_ENV === 'production' ? 'Internal Server Error' : err.message,
  });
});
```

Also handle `uncaughtException` / `unhandledRejection` so the process fails fast rather than running in a broken state:

```js
process.on('unhandledRejection', (reason) => { console.error(reason); process.exit(1); });
process.on('uncaughtException', (err) => { console.error(err); process.exit(1); });
```

## 3. No input validation

Neither route currently accepts input, but as soon as you add query params, path params, or a body, validate with a schema library (e.g., `zod`, `joi`, `express-validator`). Example pattern for a future `/users/:id`:

```js
const { z } = require('zod');
const idSchema = z.coerce.number().int().positive();

app.get('/users/:id', (req, res, next) => {
  const parsed = idSchema.safeParse(req.params.id);
  if (!parsed.success) return res.status(400).json({ error: 'Invalid id' });
  // ... lookup
});
