app.use(helmet());
app.use(express.json({ limit: '10kb' }));

// Global rate limiter — tune per-route as needed
app.use(rateLimit({
  windowMs: 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
}));

// --- Routes ---
