  // Log full error server-side; never return stack to client
  console.error({ msg: 'request_error', err: err.message, stack: err.stack });
  const status = err.status || 500;
  res.status(status).json({
    error: status === 500 ? 'Internal server error' : err.message,
  });
});

// --- Server lifecycle ---
